export function resolveTransportIndexA(action: string, index: number, total: number): number {
  if (total <= 0) {
    return -1
  }
  if (action === 'next') {
    return (index + 1) % total
  }
  if (action === 'prev') {
    return (index - 1 + total) % total
  }
  return Math.min(Math.max(index, 0), total - 1)
}

