export function nextPlayModeA(mode: string): string {
  const order: string[] = ['loop', 'single', 'shuffle']
  let i = order.indexOf(mode)
  if (i < 0) {
    i = 0
  }
  const next = (i + 1) % order.length
  return order[next]
}

