export function removeFromQueueA(queue: string[], target: number): string[] {
  if (target < 0 || target >= queue.length) {
    return queue.slice()
  }
  const result: string[] = []
  for (let i = 0; i < queue.length; i++) {
    if (i !== target) {
      result.push(queue[i])
    }
  }
  return result
}

