export function clampPlaybackSpeedA(speed: number): number {
  const MIN = 0.25
  const MAX = 4.0
  const STEP = 0.05
  if (Number.isNaN(speed)) {
    return 1.0
  }
  const clamped = Math.min(MAX, Math.max(MIN, speed))
  const stepped = Math.round(clamped / STEP) * STEP
  return Math.round(stepped * 100) / 100
}

