export function seekPositionFromRatioA(ratio: number, durationMs: number): number {
  if (durationMs <= 0) {
    return 0
  }
  let r = ratio
  if (r < 0) {
    r = 0
  } else if (r > 1) {
    r = 1
  }
  const pos = Math.round(r * durationMs)
  return Math.min(pos, durationMs)
}

